//! Class DSL parser for the unit class system.
//!
//! Classes define stat growth, scaling bonuses, abilities, and requirements.
//! The DSL is designed to be generated by the LFM at runtime and validated
//! before being applied to the game.
//!
//! Grammar:
//! ```text
//! class <Name> {
//!     stat_growth: +N attack, +N defense, ... per level
//!
//!     scaling <source> {
//!         when <condition>: <bonus>
//!         always: <bonus>
//!     }
//!
//!     abilities {
//!         level N: <ability_name> "<description>"
//!     }
//!
//!     requirements: <condition>, <condition>, ...
//!     consolidates_at: N
//! }
//! ```

use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// Class definition (output of parsing)
// ---------------------------------------------------------------------------

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct ClassDef {
    pub name: String,
    pub stat_growth: StatGrowth,
    pub scalings: Vec<ScalingBlock>,
    pub abilities: Vec<AbilityUnlock>,
    pub requirements: Vec<Requirement>,
    pub consolidates_at: Option<u32>,
}

#[derive(Clone, Debug, Default, Serialize, Deserialize)]
pub struct StatGrowth {
    pub attack: f32,
    pub defense: f32,
    pub speed: f32,
    pub max_hp: f32,
    pub ability_power: f32,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct ScalingBlock {
    pub source: String,
    pub rules: Vec<ScalingRule>,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct ScalingRule {
    pub condition: ScalingCondition,
    pub bonus: ScalingBonus,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub enum ScalingCondition {
    Always,
    When { variable: String, op: CompareOp, value: f32 },
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub enum CompareOp {
    Gt,
    Gte,
    Lt,
    Lte,
    Eq,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub enum ScalingBonus {
    /// +N% stat
    StatPercent { stat: String, percent: f32 },
    /// +N stat (flat)
    StatFlat { stat: String, value: f32 },
    /// Combat mechanic (tenacity, escape, last_stand, etc.)
    Mechanic { name: String, value: f32 },
    /// Aura — buff to nearby allies
    Aura { stat: String, value: f32 },
    /// Conditional mechanic (e.g. last_stand below 20% hp)
    ConditionalMechanic { name: String, trigger: String, value: f32 },
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct AbilityUnlock {
    pub level: u32,
    pub name: String,
    pub description: String,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub enum Requirement {
    Level(u32),
    Fame(f32),
    Trait(String),
    QuestsCompleted(usize),
    ActiveCrisis,
    GoldInvested(f32),
    GroupSize(usize),
    AlliedFactions(usize),
}

// ---------------------------------------------------------------------------
// Parser
// ---------------------------------------------------------------------------

#[derive(Debug)]
pub struct ParseError {
    pub line: usize,
    pub message: String,
}

impl std::fmt::Display for ParseError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "line {}: {}", self.line, self.message)
    }
}

/// Parse a class DSL string into a ClassDef.
pub fn parse_class(input: &str) -> Result<ClassDef, ParseError> {
    let lines: Vec<(usize, &str)> = input
        .lines()
        .enumerate()
        .map(|(i, l)| (i + 1, l.trim()))
        .filter(|(_, l)| !l.is_empty() && !l.starts_with('#'))
        .collect();

    if lines.is_empty() {
        return Err(ParseError { line: 0, message: "empty input".into() });
    }

    // Parse header: "class Name {"
    let (header_line, header) = lines[0];
    let name = parse_class_header(header)
        .ok_or(ParseError { line: header_line, message: "expected 'class <Name> {'".into() })?;

    let mut def = ClassDef {
        name,
        stat_growth: StatGrowth::default(),
        scalings: Vec::new(),
        abilities: Vec::new(),
        requirements: Vec::new(),
        consolidates_at: None,
    };

    let mut i = 1;
    while i < lines.len() {
        let (line_num, line) = lines[i];

        if line == "}" {
            break;
        }

        if line.starts_with("stat_growth:") {
            def.stat_growth = parse_stat_growth(line, line_num)?;
        } else if line.starts_with("scaling ") {
            let (block, consumed) = parse_scaling_block(&lines[i..], line_num)?;
            def.scalings.push(block);
            i += consumed;
            continue;
        } else if line.starts_with("abilities {") || line == "abilities{" {
            let (abilities, consumed) = parse_abilities_block(&lines[i..], line_num)?;
            def.abilities = abilities;
            i += consumed;
            continue;
        } else if line.starts_with("requirements:") {
            def.requirements = parse_requirements(line, line_num)?;
        } else if line.starts_with("consolidates_at:") {
            let val = line.trim_start_matches("consolidates_at:").trim();
            def.consolidates_at = Some(
                val.parse::<u32>()
                    .map_err(|_| ParseError { line: line_num, message: format!("invalid consolidation level: {}", val) })?
            );
        }

        i += 1;
    }

    Ok(def)
}

fn parse_class_header(line: &str) -> Option<String> {
    let line = line.trim();
    if !line.starts_with("class ") || !line.ends_with('{') {
        return None;
    }
    let name = line
        .trim_start_matches("class ")
        .trim_end_matches('{')
        .trim();
    if name.is_empty() {
        return None;
    }
    Some(name.to_string())
}

fn parse_stat_growth(line: &str, line_num: usize) -> Result<StatGrowth, ParseError> {
    let body = line
        .trim_start_matches("stat_growth:")
        .trim()
        .trim_end_matches("per level")
        .trim();

    let mut growth = StatGrowth::default();

    for part in body.split(',') {
        let part = part.trim();
        if part.is_empty() {
            continue;
        }

        // Parse "+N stat" or "+N all"
        let (val_str, stat) = if let Some(rest) = part.strip_prefix('+') {
            let mut tokens = rest.trim().splitn(2, ' ');
            let val = tokens.next().unwrap_or("0");
            let stat = tokens.next().unwrap_or("");
            (val, stat.trim())
        } else {
            return Err(ParseError {
                line: line_num,
                message: format!("expected '+N stat', got '{}'", part),
            });
        };

        let val: f32 = val_str.parse().map_err(|_| ParseError {
            line: line_num,
            message: format!("invalid number: {}", val_str),
        })?;

        match stat {
            "attack" => growth.attack = val,
            "defense" => growth.defense = val,
            "speed" => growth.speed = val,
            "hp" | "max_hp" => growth.max_hp = val,
            "ability_power" | "ap" => growth.ability_power = val,
            "all" => {
                growth.attack = val;
                growth.defense = val;
                growth.speed = val;
                growth.max_hp = val;
                growth.ability_power = val;
            }
            _ => {
                return Err(ParseError {
                    line: line_num,
                    message: format!("unknown stat: {}", stat),
                });
            }
        }
    }

    Ok(growth)
}

fn parse_scaling_block(
    lines: &[(usize, &str)],
    _start_line: usize,
) -> Result<(ScalingBlock, usize), ParseError> {
    let (line_num, header) = lines[0];
    let source = header
        .trim_start_matches("scaling ")
        .trim_end_matches('{')
        .trim()
        .to_string();

    if source.is_empty() {
        return Err(ParseError {
            line: line_num,
            message: "scaling block needs a source name".into(),
        });
    }

    let mut rules = Vec::new();
    let mut consumed = 1;

    for &(ln, line) in &lines[1..] {
        consumed += 1;
        if line == "}" {
            break;
        }

        let rule = if line.starts_with("when ") {
            parse_when_rule(line, ln)?
        } else if line.starts_with("always:") {
            let bonus_str = line.trim_start_matches("always:").trim();
            ScalingRule {
                condition: ScalingCondition::Always,
                bonus: parse_bonus(bonus_str, ln)?,
            }
        } else {
            return Err(ParseError {
                line: ln,
                message: format!("expected 'when ...' or 'always:', got '{}'", line),
            });
        };

        rules.push(rule);
    }

    Ok((ScalingBlock { source, rules }, consumed))
}

fn parse_when_rule(line: &str, line_num: usize) -> Result<ScalingRule, ParseError> {
    // "when <variable> <op> <value>: <bonus>"
    let body = line.trim_start_matches("when ").trim();
    let colon_pos = body.find(':').ok_or(ParseError {
        line: line_num,
        message: "missing ':' after condition".into(),
    })?;

    let cond_str = body[..colon_pos].trim();
    let bonus_str = body[colon_pos + 1..].trim();

    let condition = parse_condition(cond_str, line_num)?;
    let bonus = parse_bonus(bonus_str, line_num)?;

    Ok(ScalingRule { condition, bonus })
}

fn parse_condition(cond: &str, line_num: usize) -> Result<ScalingCondition, ParseError> {
    // Try "variable op value" patterns
    for (op_str, op) in &[
        (">=", CompareOp::Gte),
        ("<=", CompareOp::Lte),
        (">", CompareOp::Gt),
        ("<", CompareOp::Lt),
        ("==", CompareOp::Eq),
    ] {
        if let Some(pos) = cond.find(op_str) {
            let variable = cond[..pos].trim().to_string();
            let value_str = cond[pos + op_str.len()..].trim();
            let value: f32 = value_str.parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid number in condition: {}", value_str),
            })?;
            return Ok(ScalingCondition::When {
                variable,
                op: op.clone(),
                value,
            });
        }
    }

    // Simple flag condition like "crisis_active" or "faction_alive"
    Ok(ScalingCondition::When {
        variable: cond.to_string(),
        op: CompareOp::Gt,
        value: 0.0,
    })
}

fn parse_bonus(bonus: &str, line_num: usize) -> Result<ScalingBonus, ParseError> {
    let bonus = bonus.trim();

    // "+N% stat"
    if bonus.starts_with('+') && bonus.contains('%') {
        let pct_pos = bonus.find('%').unwrap();
        let val_str = &bonus[1..pct_pos];
        let stat = bonus[pct_pos + 1..].trim().to_string();
        let percent: f32 = val_str.parse().map_err(|_| ParseError {
            line: line_num,
            message: format!("invalid percent: {}", val_str),
        })?;
        return Ok(ScalingBonus::StatPercent { stat, percent });
    }

    // "+N stat" (flat)
    if bonus.starts_with('+') && !bonus.contains('%') {
        let rest = &bonus[1..];
        let mut tokens = rest.trim().splitn(2, ' ');
        if let (Some(val_str), Some(stat)) = (tokens.next(), tokens.next()) {
            let value: f32 = val_str.parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid number: {}", val_str),
            })?;
            return Ok(ScalingBonus::StatFlat {
                stat: stat.trim().to_string(),
                value,
            });
        }
    }

    // "aura stat +N"
    if bonus.starts_with("aura ") {
        let rest = bonus.trim_start_matches("aura ").trim();
        let mut tokens = rest.splitn(2, ' ');
        if let (Some(stat), Some(val_str)) = (tokens.next(), tokens.next()) {
            let val_str = val_str.trim().trim_start_matches('+');
            let value: f32 = val_str.parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid aura value: {}", val_str),
            })?;
            return Ok(ScalingBonus::Aura {
                stat: stat.to_string(),
                value,
            });
        }
    }

    // "mechanic_name value" (tenacity 0.5, escape, etc.)
    // Or "mechanic_name condition value" (last_stand below 20% +100% attack)
    if bonus.contains("below") || bonus.contains("above") {
        // Conditional mechanic: "last_stand below 20% hp +100% attack"
        let mut tokens = bonus.splitn(2, ' ');
        let name = tokens.next().unwrap_or("").to_string();
        let trigger = tokens.next().unwrap_or("").to_string();
        return Ok(ScalingBonus::ConditionalMechanic {
            name,
            trigger,
            value: 0.0,
        });
    }

    // Simple mechanic: "tenacity 0.5"
    let mut tokens = bonus.splitn(2, ' ');
    let name = tokens.next().unwrap_or("").to_string();
    let value: f32 = tokens
        .next()
        .and_then(|s| s.trim().parse().ok())
        .unwrap_or(1.0);

    Ok(ScalingBonus::Mechanic { name, value })
}

fn parse_abilities_block(
    lines: &[(usize, &str)],
    _start_line: usize,
) -> Result<(Vec<AbilityUnlock>, usize), ParseError> {
    let mut abilities = Vec::new();
    let mut consumed = 1;

    for &(ln, line) in &lines[1..] {
        consumed += 1;
        if line == "}" {
            break;
        }

        // "level N: ability_name "description""
        if line.starts_with("level ") {
            let rest = line.trim_start_matches("level ").trim();
            let colon_pos = rest.find(':').ok_or(ParseError {
                line: ln,
                message: "expected 'level N: ability_name'".into(),
            })?;

            let level: u32 = rest[..colon_pos].trim().parse().map_err(|_| ParseError {
                line: ln,
                message: "invalid level number".into(),
            })?;

            let after_colon = rest[colon_pos + 1..].trim();

            // Split ability name from optional description in quotes
            let (name, description) = if let Some(quote_start) = after_colon.find('"') {
                let name = after_colon[..quote_start].trim().to_string();
                let desc = after_colon[quote_start + 1..]
                    .trim_end_matches('"')
                    .to_string();
                (name, desc)
            } else {
                (after_colon.to_string(), String::new())
            };

            abilities.push(AbilityUnlock {
                level,
                name,
                description,
            });
        }
    }

    Ok((abilities, consumed))
}

fn parse_requirements(line: &str, line_num: usize) -> Result<Vec<Requirement>, ParseError> {
    let body = line.trim_start_matches("requirements:").trim();
    let mut reqs = Vec::new();

    for part in body.split(',') {
        let part = part.trim();
        if part.is_empty() {
            continue;
        }

        if part.starts_with("level ") {
            let val: u32 = part[6..].trim().parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid level requirement: {}", part),
            })?;
            reqs.push(Requirement::Level(val));
        } else if part.starts_with("fame ") || part.starts_with("fame>=") {
            let val_str = part
                .trim_start_matches("fame ")
                .trim_start_matches("fame>=")
                .trim_start_matches('>').trim_start_matches('=')
                .trim();
            let val: f32 = val_str.parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid fame requirement: {}", part),
            })?;
            reqs.push(Requirement::Fame(val));
        } else if part.starts_with("trait ") {
            reqs.push(Requirement::Trait(part[6..].trim().to_string()));
        } else if part.starts_with("quests ") {
            let val: usize = part[7..].trim().parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid quests requirement: {}", part),
            })?;
            reqs.push(Requirement::QuestsCompleted(val));
        } else if part == "active_crisis" {
            reqs.push(Requirement::ActiveCrisis);
        } else if part.starts_with("gold ") {
            let val: f32 = part[5..].trim().parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid gold requirement: {}", part),
            })?;
            reqs.push(Requirement::GoldInvested(val));
        } else if part.starts_with("group_size ") {
            let val: usize = part[11..].trim().parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid group_size requirement: {}", part),
            })?;
            reqs.push(Requirement::GroupSize(val));
        } else if part.starts_with("allies ") {
            let val: usize = part[7..].trim().parse().map_err(|_| ParseError {
                line: line_num,
                message: format!("invalid allies requirement: {}", part),
            })?;
            reqs.push(Requirement::AlliedFactions(val));
        } else {
            return Err(ParseError {
                line: line_num,
                message: format!("unknown requirement: {}", part),
            });
        }
    }

    Ok(reqs)
}

// ---------------------------------------------------------------------------
// Validation
// ---------------------------------------------------------------------------

/// Validate a parsed class definition for sane values.
pub fn validate_class(def: &ClassDef) -> Vec<String> {
    let mut errors = Vec::new();

    if def.name.is_empty() {
        errors.push("class name is empty".into());
    }

    // Check stat growth isn't absurd
    let total_growth = def.stat_growth.attack + def.stat_growth.defense
        + def.stat_growth.speed + def.stat_growth.max_hp + def.stat_growth.ability_power;
    if total_growth > 50.0 {
        errors.push(format!("stat growth per level ({}) seems too high (max 50)", total_growth));
    }
    if total_growth < 0.0 {
        errors.push("stat growth per level is negative".into());
    }

    // Check scaling sources are known
    let valid_sources = [
        "party_alive_count", "party_size", "faction_strength", "coalition_strength",
        "crisis_severity", "fame", "territory_control", "adventurer_count",
        "gold", "reputation", "threat_level",
    ];
    for block in &def.scalings {
        if !valid_sources.contains(&block.source.as_str()) {
            errors.push(format!("unknown scaling source: {}", block.source));
        }
    }

    // Check ability levels are in order
    let mut last_level = 0;
    for ability in &def.abilities {
        if ability.level < last_level {
            errors.push(format!(
                "ability '{}' at level {} is out of order (previous was {})",
                ability.name, ability.level, last_level
            ));
        }
        last_level = ability.level;
        if ability.level > 100 {
            errors.push(format!("ability '{}' level {} exceeds cap (100)", ability.name, ability.level));
        }
    }

    if let Some(consol) = def.consolidates_at {
        if consol > 20 {
            errors.push(format!("consolidation level {} seems high", consol));
        }
    }

    errors
}

// ---------------------------------------------------------------------------
// Loading from files
// ---------------------------------------------------------------------------

/// Load class definitions from .class files in a directory.
pub fn load_classes_from_dir(dir: &std::path::Path) -> Vec<ClassDef> {
    let mut classes = Vec::new();
    if !dir.exists() {
        return classes;
    }
    let entries = match std::fs::read_dir(dir) {
        Ok(e) => e,
        Err(_) => return classes,
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.extension().and_then(|e| e.to_str()) != Some("class") {
            continue;
        }
        match std::fs::read_to_string(&path) {
            Ok(content) => match parse_class(&content) {
                Ok(def) => {
                    let validation = validate_class(&def);
                    if validation.is_empty() {
                        classes.push(def);
                    } else {
                        eprintln!("Warning: class {} has validation errors:", path.display());
                        for err in &validation {
                            eprintln!("  {}", err);
                        }
                    }
                }
                Err(e) => eprintln!("Warning: failed to parse {}: {}", path.display(), e),
            },
            Err(e) => eprintln!("Warning: failed to read {}: {}", path.display(), e),
        }
    }
    classes
}

static CLASSES: std::sync::OnceLock<Vec<ClassDef>> = std::sync::OnceLock::new();

pub fn get_or_load_classes() -> &'static Vec<ClassDef> {
    CLASSES.get_or_init(|| {
        let dir = std::path::Path::new("assets/classes");
        let classes = load_classes_from_dir(dir);
        if !classes.is_empty() {
            eprintln!("Classes: loaded {} from {}", classes.len(), dir.display());
        }
        classes
    })
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_basic_class() {
        let input = r#"
class Ranger {
    stat_growth: +2 attack, +1 defense, +3 speed per level

    scaling party_alive_count {
        when party_members > 0: tenacity 0.5
        when party_members >= 3: +15% defense
        always: aura morale +2
    }

    abilities {
        level 1: keen_eye "Increased scout range"
        level 5: multishot "Attacks hit 2 targets"
        level 10: camouflage "Can escape combat"
    }

    requirements: level 1
}
"#;
        let def = parse_class(input).expect("should parse");
        assert_eq!(def.name, "Ranger");
        assert_eq!(def.stat_growth.attack, 2.0);
        assert_eq!(def.stat_growth.speed, 3.0);
        assert_eq!(def.scalings.len(), 1);
        assert_eq!(def.scalings[0].source, "party_alive_count");
        assert_eq!(def.scalings[0].rules.len(), 3);
        assert_eq!(def.abilities.len(), 3);
        assert_eq!(def.abilities[0].name, "keen_eye");

        let errors = validate_class(&def);
        assert!(errors.is_empty(), "validation errors: {:?}", errors);
    }

    #[test]
    fn test_parse_hero_class() {
        let input = r#"
class Hero {
    stat_growth: +5 all per level

    scaling crisis_severity {
        when crisis_active: +20% all_stats
        when crisis_severity > 500: last_stand below 20% hp +100% attack
    }

    abilities {
        level 1: rallying_cry "Allies gain attack"
        level 10: consolidation "Merge with primary class"
    }

    requirements: fame 2000, active_crisis
    consolidates_at: 10
}
"#;
        let def = parse_class(input).expect("should parse");
        assert_eq!(def.name, "Hero");
        assert_eq!(def.stat_growth.attack, 5.0);
        assert_eq!(def.stat_growth.defense, 5.0);
        assert_eq!(def.consolidates_at, Some(10));
        assert_eq!(def.requirements.len(), 2);
    }

    #[test]
    fn test_reject_invalid_stat() {
        let input = r#"
class Bad {
    stat_growth: +5 charisma per level
}
"#;
        let result = parse_class(input);
        assert!(result.is_err());
    }

    #[test]
    fn test_validate_absurd_growth() {
        let input = r#"
class Broken {
    stat_growth: +100 all per level
}
"#;
        let def = parse_class(input).expect("should parse");
        let errors = validate_class(&def);
        assert!(!errors.is_empty(), "should flag absurd growth");
    }
}
